                </div>
            </div>

            <div class="filter-actions">
                <button class="btn btn-primary w-100 mb-2" @onclick="ApplyFiltersAsync">Apply Filters</button>
                <button class="btn btn-outline-secondary w-100" @onclick="ClearFiltersAsync">Clear Filters</button>
            </div>
        </aside>

        <!-- Main Content Area -->
        <section class="catalog-main">
            <!-- Toolbar -->
            <div class="catalog-toolbar">
                <div class="d-flex align-items-center gap-3">
