                            <button class="page-link" disabled="@(currentPage >= totalPages)"
                                    @onclick="() => GoToPageAsync(currentPage + 1)">Next</button>
                        </li>
                    </ul>
                </nav>
            }
        </section>
    </div>
}

@code {
    private List<string>? categories;
    private HashSet<string> selectedCategories = new();
    private decimal? minPrice;
    private decimal? maxPrice;
    private bool inStockOnly;
    private string sortBy = "price_asc";
    private int currentPage = 1;
    private const int PageSize = 12;
    private PagedResult<Product>? result;
    private bool isLoading = true;
    private string? errorMessage;

    private int totalPages => result is null || result.PageSize == 0
        ? 1
        : (int)Math.Ceiling((double)result.TotalCount / result.PageSize);

    protected override async Task OnInitializedAsync()
    {
        await LoadDataAsync();
    }

    private async Task LoadDataAsync()
    {
        try
        {
            isLoading = true;
            errorMessage = null;

            var categoriesTask = categories is null
                ? ProductService.GetCategoriesAsync()
                : Task.FromResult(categories);
            var searchTask = SearchProductsAsync();

            await Task.WhenAll(categoriesTask, searchTask);
            categories = await categoriesTask;
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task SearchProductsAsync()
    {
        isLoading = true;
        errorMessage = null;

        try
        {
            var filter = new ProductFilter(
                Categories: selectedCategories.Count > 0 ? selectedCategories.ToList() : null,
                MinPrice: minPrice,
                MaxPrice: maxPrice,
                InStockOnly: inStockOnly
            );
            result = await ProductService.SearchAsync(filter, sortBy, currentPage, PageSize);
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            selectedCategories.Add(category);
        else
            selectedCategories.Remove(category);
    }

    private async Task ApplyFiltersAsync()
    {
        currentPage = 1;
        await SearchProductsAsync();
    }

    private async Task ClearFiltersAsync()
    {
        selectedCategories.Clear();
        minPrice = null;
        maxPrice = null;
        inStockOnly = false;
        currentPage = 1;
        await SearchProductsAsync();
    }

    private async Task OnSortChangedAsync()
    {
        currentPage = 1;
        await SearchProductsAsync();
    }

    private async Task GoToPageAsync(int page)
    {
        if (page < 1 || page > totalPages) return;
        currentPage = page;
        await SearchProductsAsync();
    }

    private async Task RetryAsync()
    {
        await LoadDataAsync();
    }

    private void OnProductSelected(Product product)
    {
        // Parent-level handler — could navigate to /catalog/{product.Id}
    }
}
"}

